#include <vector>
#include <algorithm>

void adaptive_sort(std::vector<int>& arr) {
    const size_t n = arr.size();
    if (n < 2) return;

    // Identify sorted prefix; skip forward if already sorted
    auto it = std::is_sorted_until(arr.begin(), arr.end());
    if (it == arr.end()) return;

    // Check for reverse-sorted data
    if (std::is_sorted(arr.rbegin(), arr.rend())) {
        std::reverse(arr.begin(), arr.end());
        return;
    }

    // Use optimized Insertion Sort for small arrays or fall back to Introsort
    if (n < 24) {
        for (; it != arr.end(); ++it) {
            int key = *it;
            auto j = it;
            while (j > arr.begin() && *(j - 1) > key) {
                *j = *(j - 1);
                --j;
            }
            *j = key;
        }
    } else {
        std::sort(arr.begin(), arr.end());
    }
}

